   204→// --- OCR Cloud Function for Expiry Date ---
   205→exports.extractExpiryDateFromImage = functions.https.onCall(async (request) => {
   206→  const data = request.data;
   207→  let imageBase64;
   208→  if (data && data.image && typeof data.image === 'string') {
   209→    imageBase64 = data.image;
   210→  } else if (data && typeof data === 'string') {
   211→    imageBase64 = data;
   212→  } else {
   213→    throw new functions.https.HttpsError('invalid-argument', 'The function must be called with a valid image string.');
   214→  }
   215→  const imageBuffer = Buffer.from(imageBase64, 'base64');
   216→  try {
   217→    const [result] = await visionClient.textDetection({
   218→      image: { content: imageBuffer },
   219→    });
   220→    const detections = result.textAnnotations;
   221→    const fullText = detections.length > 0 ? detections[0].description : '';
   222→    console.log('Full text detected:', fullText);
   223→    const datePatterns = [
   224→      /(\d{2})[.\/-](\d{2})[.\/-](\d{4})/,
   225→      /(\d{4})[.\/-](\d{2})[.\/-](\d{2})/,
   226→      /(\d{2})\s(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\s(\d{4})/i,
   227→      /(\d{2})\s(\d{2})\s(\d{4})/
   228→    ];
   229→    let detectedDate = null;
   230→    for (const pattern of datePatterns) {
   231→      const match = fullText.match(pattern);
   232→      if (match) {
   233→        if (pattern === datePatterns[0] || pattern === datePatterns[3]) {
   234→          const [ , day, month, year ] = match;
   235→          detectedDate = `${year}-${month}-${day}`;
   236→        } else if (pattern === datePatterns[1]) {
   237→          const [ , year, month, day ] = match;
   238→          detectedDate = `${year}-${month}-${day}`;
   239→        } else if (pattern === datePatterns[2]) {
   240→          const [ , day, monthStr, year ] = match;
   241→          const monthMap = {
   242→            jan: '01', feb: '02', mar: '03', apr: '04', may: '05', jun: '06',
   243→            jul: '07', aug: '08', sep: '09', oct: '10', nov: '11', dec: '12'
   244→          };
   245→          const month = monthMap[monthStr.toLowerCase()];
   246→          detectedDate = `${year}-${month}-${day}`;
   247→        }
   248→        break;
   249→      }
   250→    }
   251→    if (detectedDate) {
   252→      return { expiryDate: detectedDate, message: 'Date détectée.' };
   253→    } else {
   254→      return { expiryDate: null, message: 'Aucune date valide trouvée dans l\'image.' };
   255→    }
   256→  } catch (error) {
   257→    console.error('Error during Vision API call or date extraction:', { message: error.message, code: error.code, stack: error.stack });
   258→    throw new functions.https.HttpsError('internal', 'Erreur lors du traitement de l\'image.', error.message);
   259→  }
   260→});
